mapper.select:
SELECT tr.id, tr.school_year AS schoolYear, grade.id AS classGroupId, grade.grade_group_name AS classGroupName, cla.department AS department, cla.id AS classId, cla.class_name AS className, tr.create_time AS createTime, tr.update_time AS updateTime, tr.registrant AS registrant, tr.registrant_id AS registrantId, tr.status AS status, tr.zip_url AS zipUrl FROM transcript_record tr LEFT JOIN sys_class cla ON cla.id = tr.class_id LEFT JOIN grade_group grade ON grade.id = tr.grade_group WHERE tr.deleted = 0
AND tr.school_id = ${reqModel.schoolId}
AND tr.school_year = #{reqModel.schoolYear}
AND tr.grade_group = ${reqModel.gradeGroup}
AND tr.class_id = ${reqModel.classId}
AND tr.department = ${reqModel.department}
AND cla.id IN
${classId}
ORDER BY tr.create_time desc
